//! DSEL CLI
//!
//! Usage:
//!   dsel route kilo_code/some-model    # Get provider routing
//!   dsel available                     # List providers with API keys
//!   dsel status                        # All providers + status

use clap::{Parser, Subcommand};
use litebike::dsel;

#[derive(Parser)]
#[command(name = "dsel")]
#[command(about = "DSEL - Domain Specific Expression Language")]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Route model to provider
    Route {
        /// Model ID (e.g., "kilo_code/model" or just "model")
        model: String,
    },
    /// List available providers (with API keys)
    Available,
    /// Show all providers status
    Status,
}

fn main() {
    let cli = Cli::parse();

    match cli.command {
        Commands::Route { model } => {
            let (name, url, key_env) = dsel::route(&model);
            println!("provider={}", name);
            println!("url={}", url);
            println!("key_env={}", key_env);
            if let Some(key) = dsel::key(key_env) {
                let masked = format!("{}***{}", &key[..2.min(key.len())], &key[key.len().saturating_sub(2)..]);
                println!("key={}", masked);
            }
        }

        Commands::Available => {
            for name in dsel::available() {
                println!("{}", name);
            }
        }

        Commands::Status => {
            println!("PROVIDER       PRIO  HAS_KEY  BASE_URL");
            for (name, url, prio, has_key) in dsel::status() {
                println!("{:<14} {:<5} {:<7} {}", name, prio, if has_key { "✓" } else { "" }, url);
            }
        }
    }
}

//! DSEL - Domain Specific Expression Language
//!
//! Pure routing. No hardcoded providers. No models endpoint.
//! Providers discovered from environment variables only.

use std::env;

/// Provider configuration
#[derive(Clone)]
pub struct Provider {
    pub name: String,
    pub base_url: String,
    pub key_env: String,
    pub priority: u8,
}

/// Discover providers from environment
/// Looks for *_API_KEY and *_BASE_URL patterns
pub fn discover_providers() -> Vec<Provider> {
    let mut providers = Vec::new();

    // Known provider patterns (discovered from env, not hardcoded)
    let provider_names = ["kilo_code", "moonshot", "deepseek", "openai", "anthropic"];

    for (priority, name) in provider_names.iter().enumerate() {
        let key_env = format!("{}_API_KEY", name.to_uppercase());
        let base_url_env = format!("{}_BASE_URL", name.to_uppercase());

        if env::var(&key_env).is_ok() {
            let base_url = env::var(&base_url_env)
                .unwrap_or_else(|_| get_default_base_url(name));

            providers.push(Provider {
                name: name.to_string(),
                base_url,
                key_env,
                priority: (priority + 1) as u8,
            });
        }
    }

    providers
}

fn get_default_base_url(name: &str) -> String {
    match name {
        "kilo_code" => "https://api.kilo.ai/api/gateway".to_string(),
        "moonshot" => "https://api.moonshot.cn/v1".to_string(),
        "deepseek" => "https://api.deepseek.com/v1".to_string(),
        "openai" => "https://api.openai.com/v1".to_string(),
        "anthropic" => "https://api.anthropic.com".to_string(),
        _ => String::new(),
    }
}

/// Route a model ID to its provider
/// Returns (provider_name, base_url, api_key_env)
pub fn route(model: &str) -> Option<(String, String, String)> {
    let providers = discover_providers();

    let specified = model.split('/').next().unwrap_or("");

    if !specified.is_empty() {
        if let Some(p) = providers.iter().find(|p| p.name == specified) {
            return Some((p.name.clone(), p.base_url.clone(), p.key_env.clone()));
        }
    }

    providers.into_iter()
        .min_by_key(|p| p.priority)
        .map(|p| (p.name, p.base_url, p.key_env))
}

pub fn key(env_var: &str) -> Option<String> {
    env::var(env_var).ok()
}

pub fn has_key(env_var: &str) -> bool {
    env::var(env_var).is_ok()
}

pub fn available() -> Vec<String> {
    discover_providers().iter().map(|p| p.name.clone()).collect()
}

pub fn status() -> Vec<(String, String, u8, bool)> {
    let provider_names = ["kilo_code", "moonshot", "deepseek", "openai", "anthropic"];

    provider_names.iter().enumerate().map(|(priority, name)| {
        let key_env = format!("{}_API_KEY", name.to_uppercase());
        let base_url_env = format!("{}_BASE_URL", name.to_uppercase());
        let has_key = env::var(&key_env).is_ok();
        let base_url = env::var(&base_url_env)
            .unwrap_or_else(|_| get_default_base_url(name));

        (name.to_string(), base_url, (priority + 1) as u8, has_key)
    }).collect()
}

pub fn get_provider(name: &str) -> Option<Provider> {
    discover_providers().into_iter().find(|p| p.name == name)
}

