                }
                SelectionCondition::CostThreshold(threshold) => {
                    if provider.calculate_cost(tokens) > *threshold {
                        return false;
                    }
                }
                SelectionCondition::FreeOnly => {
                    if !provider.is_free {
                        return false;
                    }
                }
                SelectionCondition::ProviderName(name) => {
                    if &provider.name != name {
                        return false;
                    }
                }
            }
        }
        true
    }
