//! DSEL CLI
//!
//! Usage:
//!   dsel route kilo_code/some-model    # Get provider routing
//!   dsel available                     # List providers with API keys
//!   dsel status                        # All providers + status
//!   dsel tokens nvidia/kimi            # Show [token in provider]/[token in model]

use clap::{Parser, Subcommand};
use litebike::dsel;

#[derive(Parser)]
#[command(name = "dsel")]
#[command(about = "DSEL - Domain Specific Expression Language")]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Route model to provider
    Route {
        /// Model ID (e.g., "kilo_code/model" or just "model")
        model: String,
    },
    /// List available providers (with API keys)
    Available,
    /// Show all providers status
    Status,
    /// Show token info [provider_tokens]/[model_tokens]
    Tokens {
        /// Model ID (e.g., "nvidia/kimi")
        model: String,
    },
}

fn main() {
    let cli = Cli::parse();

    match cli.command {
        Commands::Route { model } => {
            if let Some((name, url, key_env)) = dsel::route(&model) {
                println!("provider={}", name);
                println!("url={}", url);
                println!("key_env={}", key_env);
                if let Some(key) = dsel::key(&key_env) {
                    let masked = format!("{}***{}", &key[..2.min(key.len())], &key[key.len().saturating_sub(2)..]);
                    println!("key={}", masked);
                }
            } else {
                println!("No provider found for model: {}", model);
            }
        }

        Commands::Available => {
            for name in dsel::available() {
                println!("{}", name);
            }
        }

        Commands::Status => {
            println!("PROVIDER       PRIO  HAS_KEY  BASE_URL");
            for (name, url, prio, has_key) in dsel::status() {
                println!("{:<14} {:<5} {:<7} {}", name, prio, if has_key { "✓" } else { "" }, url);
            }
        }

        Commands::Tokens { model } => {
            // Parse provider from model path
            let provider = model.split('/').next().unwrap_or("");

            // Get provider token info from DSEL quota tracking
            let provider_tokens = get_provider_tokens(provider);

            // Get model token limit (from model cards or default)
            let model_tokens = get_model_tokens(&model);

            // Display: [provider_tokens]/[model_tokens]
            println!("{}/{}",
                format_tokens(provider_tokens),
                format_tokens(model_tokens)
            );
        }
    }
}

/// Get provider token quota (estimated remaining)
fn get_provider_tokens(provider: &str) -> u64 {
    match provider {
        "nvidia" => 3_000_000,      // NVIDIA estimated daily limit
        "kilo_code" => 1_000_000,   // KiloCode estimated daily limit
        "opencode" => 500_000,      // OpenCode estimated daily limit
        "openrouter" => 2_000_000,  // OpenRouter estimated daily limit
        _ => 100_000,               // Default for unknown providers
    }
}

/// Get model-specific token limit
fn get_model_tokens(model: &str) -> u64 {
    // Model-specific token limits (can be extended with model card lookup)
    match model {
        "nvidia/kimi" => 128_000,           // Kimi context window
        "nvidia/llama" => 32_768,           // LLaMA typical context
        "kilo_code/*" => 100_000,           // Default for kilo_code models
        _ => 32_768,                        // Default context window
    }
}

/// Format token count with underscores for readability
fn format_tokens(tokens: u64) -> String {
    if tokens >= 1_000_000 {
        format!("{}M", tokens / 1_000_000)
    } else if tokens >= 1_000 {
        format!("{}K", tokens / 1_000)
    } else {
        tokens.to_string()
    }
}

